//! The /v1 API contract (D69): one typed struct per operation shape.
//!
//! This is the ONLY crate where serde/utoipa derives are legal. The
//! house no-derive rule exists because CAS object encodings ARE
//! identities (D18) — a macro must never own load-bearing bytes; D69
//! scopes that ban to canonical/content-addressed encodings. The HTTP
//! API is not that: it is a versioned, negotiable surface, so it gets
//! real types, and three consumers hang off them — the daemon's
//! handlers (datboi-server), the CHECKED-IN OpenAPI 3.1 spec
//! (`openapi.json`, regenerated by
//! `cargo run -p datboi-api --bin datboi-gen-openapi`, pinned byte-for-byte
//! by a test in this crate), and the web UI's generated TS client.
//!
//! Contract scope is exactly `/v1`. The minted-image download
//! (`GET /v1/views/{name}/image`) is in scope as an octet-stream
//! operation; the non-/v1 surfaces — the `/view/*` and `/snap/*` byte
//! trees (HTML/JSON listings, Range serving), `/dav`, NFS, and the
//! embedded UI fallback — are serving surfaces, not API operations,
//! and deliberately stay out of the spec.
//!
//! Field-level fidelity rule: these structs describe what actually
//! goes over the wire TODAY, and the wire mode rides the field's TYPE
//! (see [`wire`]): always-present-but-nullable is [`Nullable<T>`];
//! omitted-when-absent is `Option<T>` with
//! `#[serde(skip_serializing_if = "Option::is_none")]`.

use serde::{Deserialize, Serialize};
use utoipa::ToSchema;

mod paths;
pub mod wire;

pub use wire::Nullable;

// ---- the uniform error shape ----

/// Every /v1 error body: `{"error": "<message>", "code": "<code>"}`.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct ApiError {
    /// Human-readable failure description — diagnostic detail for CLI
    /// and log consumers. The web UI presents `code`, not this.
    pub error: String,
    /// Machine-readable failure category (D77).
    pub code: ErrorCode,
}

/// Machine-readable failure category (D77). A CLOSED union: the web UI
/// maps every variant to a translated message through an exhaustive
/// switch, so adding a variant here fails the web typecheck until that
/// message exists — errors are translatable by construction, never by
/// passing English prose through.
///
/// The HTTP status derives FROM the code ([`ErrorCode::http_status`]),
/// so a handler cannot pair a code with a contradicting status.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
#[serde(rename_all = "snake_case")]
pub enum ErrorCode {
    /// Malformed request shape or parameter values. The UI validates
    /// before sending, so reaching this implies a bug or a hand-built
    /// request — the `error` detail matters more than usual.
    BadRequest,
    /// The staged-upload token is unknown or expired: the fix is to
    /// upload again, and the UI should say so.
    UploadExpired,
    /// Authentication required (no/dead session, or a loopback-only
    /// surface reached from elsewhere).
    Unauthorized,
    /// Login refused: bad username or password — a typed answer, never
    /// session death.
    InvalidCredentials,
    /// Authenticated, but this resource is owner-only.
    OwnerOnly,
    /// The invite token is invalid, already spent, or expired.
    InvalidInvite,
    /// The Fetch-Metadata CSRF gate rejected a cross-origin request.
    CsrfRejected,
    /// The requested resource does not exist.
    NotFound,
    /// Invite acceptance raced a name: that username is taken.
    UsernameTaken,
    /// A conflicting maintenance task holds the guard; retry shortly.
    Busy,
    /// The store lacks headroom for the declared upload size.
    StoreFull,
    /// The daemon failed internally; the `error` detail is diagnostic.
    Internal,
}

impl ErrorCode {
    /// The one HTTP status this code rides — the pairing lives here so
    /// call sites cannot disagree about it.
    pub fn http_status(self) -> u16 {
        match self {
            Self::BadRequest | Self::UploadExpired => 400,
            Self::Unauthorized | Self::InvalidCredentials => 401,
            Self::OwnerOnly | Self::InvalidInvite | Self::CsrfRejected => 403,
            Self::NotFound => 404,
            Self::UsernameTaken => 409,
            Self::Busy => 503,
            Self::StoreFull => 507,
            Self::Internal => 500,
        }
    }
}

/// The `{"ok": true}` acknowledgement mutations answer with.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct OkResponse {
    pub ok: bool,
}

// ---- shared vocabulary enums (lowercase on the wire) ----

/// User roles (D30/D68): owners see everything, friends see grants.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
#[serde(rename_all = "lowercase")]
pub enum Role {
    Owner,
    Friend,
}

/// How a caller's identity arrived (whoami reports it). `loopback` is
/// the D68 implicit owner — a local shell already owns the daemon's
/// files.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
#[serde(rename_all = "lowercase")]
pub enum Via {
    Loopback,
    Session,
    Bearer,
}

/// The UI's 4-state per-entry vocabulary, derived from the D39 rollup
/// (web spec §7). `nodump` entries are excluded from completeness math
/// client-side.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
#[serde(rename_all = "lowercase")]
pub enum EntryState {
    Verified,
    Claimed,
    Missing,
    Nodump,
}

/// Per-claim rollup state — the entry vocabulary plus the two
/// non-holding grades (`peer`, `probable`) that fold into `missing` at
/// entry granularity.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
#[serde(rename_all = "lowercase")]
pub enum ClaimState {
    Verified,
    Claimed,
    Peer,
    Probable,
    Missing,
    Nodump,
}

/// Blob residency (D21): bytes on disk, evicted-but-rebuildable, or
/// known-absent.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
#[serde(rename_all = "snake_case")]
pub enum ResidencyState {
    Resident,
    EvictedCovered,
    Absent,
}

/// Recipe verification grade (D25); `failed` recipes are poisoned and
/// never surface as routes.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
#[serde(rename_all = "snake_case")]
pub enum RouteVerify {
    Pending,
    Verified,
    ReplayedLocal,
}

/// 1G1R selection mode (D57): `strict` is a pure function of
/// (dat, preferences); `held_first` prefers what you actually have.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
#[serde(rename_all = "snake_case")]
pub enum OneGOneRMode {
    Strict,
    HeldFirst,
}

/// MAME set rendering mode (D31 deferred set).
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
#[serde(rename_all = "kebab-case")]
pub enum MameMode {
    NonMerged,
    Split,
    Merged,
}

// ---- GET /v1/auth/whoami ----

/// Whoami is open by design: it answers `authenticated: false` instead
/// of 401 so the SPA can probe without special-casing errors.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct WhoamiResponse {
    pub authenticated: bool,
    /// Absent for loopback (no user row) and anonymous callers.
    #[serde(skip_serializing_if = "Option::is_none")]
    pub username: Option<String>,
    /// Absent when unauthenticated.
    #[serde(skip_serializing_if = "Option::is_none")]
    pub role: Option<Role>,
    /// Absent when unauthenticated.
    #[serde(skip_serializing_if = "Option::is_none")]
    pub via: Option<Via>,
}

// ---- POST /v1/auth/login + /v1/auth/invite/accept ----

/// Login credentials. Missing fields are the extractor's typed 400
/// (datboi-server's `ApiJson` keeps every body-parse failure in the
/// D69 error shape), so plain `String` IS the required-field contract.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct LoginRequest {
    pub username: String,
    pub password: String,
}

/// Invite acceptance: consumes the invite atomically, creates the user
/// with the invite's role, and starts a session.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct InviteAcceptRequest {
    /// The invite token exactly as minted (the URL fragment).
    pub token: String,
    /// 1-32 characters of `[a-z0-9_-]`.
    pub username: String,
    /// At least 8 characters.
    pub password: String,
}

/// A fresh login/acceptance answer: whoami-shaped plus the session
/// expiry. The session token itself rides the `Set-Cookie` header
/// (HttpOnly), never the body.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct SessionResponse {
    pub authenticated: bool,
    pub username: String,
    pub role: Role,
    /// Unix seconds.
    pub expires_at: i64,
}

// ---- GET /v1/systems ----

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct SystemsResponse {
    pub systems: Vec<System>,
}

/// A "system" is a `dat_source` row. `id` is a cache.db surrogate —
/// stable while the cache lives, re-minted by `datboi recover`;
/// clients treat it as a handle, not an identity (the durable identity
/// is provider/system).
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct System {
    pub id: i64,
    pub provider: String,
    pub system: String,
    /// `provider/system`, the durable display identity.
    pub source: String,
    /// Null when the source exists but nothing was imported yet.
    pub revision: Nullable<Revision>,
    pub counts: Counts,
    /// Total entries in the current revision (counts sum to this).
    pub total: i64,
    /// Stored ViewDef names referencing this source.
    pub views: Vec<String>,
}

/// One imported dat revision.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct Revision {
    pub id: i64,
    pub version: Nullable<String>,
    pub date: Nullable<String>,
    /// Unix seconds.
    pub imported_at: Nullable<i64>,
}

/// The D39 entry-audit rollup, bucketed into the 4-state vocabulary.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct Counts {
    pub verified: i64,
    pub claimed: i64,
    pub missing: i64,
    pub nodump: i64,
}

// ---- GET /v1/systems/{id}/entries ----

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct EntriesPage {
    pub entries: Vec<EntryRow>,
    /// The FILTERED count; the offset/limit window slides under it.
    pub total: i64,
    pub offset: u64,
    pub limit: u64,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct EntryRow {
    pub name: String,
    pub state: EntryState,
    /// Total required bytes — null unless every required claim
    /// declares a size.
    pub size: Nullable<i64>,
    /// Best hash of the single required claim, full hex — null when
    /// the entry wants zero or several ROMs (the detail endpoint has
    /// them all).
    pub wanted_hash: Nullable<String>,
    /// `sha256` | `sha1` | `md5` | `crc32`, strongest available.
    pub wanted_hash_algo: Nullable<String>,
}

// ---- GET /v1/systems/{id}/entries/{name} ----

/// Entry detail is keyed by NAME (`UNIQUE(revision_id, name)` within a
/// revision; claim names are not unique — MAME sets repeat them).
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct EntryDetail {
    pub name: String,
    pub state: EntryState,
    pub size: Nullable<i64>,
    pub wanted_hash: Nullable<String>,
    pub wanted_hash_algo: Nullable<String>,
    pub revision: Revision,
    pub roms: Vec<RomClaim>,
}

/// One rom claim with its rollup state and, when a local blob
/// satisfies it, the resolved blob + rebuild routes + pin list.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct RomClaim {
    pub name: String,
    pub size: Nullable<i64>,
    pub state: ClaimState,
    pub optional: bool,
    /// Declared digests, lowercase hex; only the algorithms the dat
    /// actually carries appear.
    pub hashes: RomHashes,
    /// The satisfying local blob (strong-basis links only, smallest
    /// hash wins) — omitted entirely when nothing satisfies the claim.
    #[serde(skip_serializing_if = "Option::is_none")]
    pub blob: Option<BlobInfo>,
    /// Rebuild routes for the resolved blob; omitted when `blob` is.
    #[serde(skip_serializing_if = "Option::is_none")]
    pub routes: Option<Vec<RouteInfo>>,
    /// Views whose CURRENT snapshots reference the resolved blob
    /// (D33: the tag is what pins); omitted when `blob` is.
    #[serde(skip_serializing_if = "Option::is_none")]
    pub pins: Option<Vec<String>>,
}

/// Declared claim digests (lowercase hex); absent algorithms are
/// omitted, not null.
#[derive(Debug, Clone, Default, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct RomHashes {
    #[serde(skip_serializing_if = "Option::is_none")]
    pub crc32: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub md5: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub sha1: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub sha256: Option<String>,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct BlobInfo {
    /// blake3, lowercase hex.
    pub hash: String,
    pub residency: ResidencyState,
    /// Last full-hash store verification (ingest or scrub), unix
    /// seconds; the index records no method, so none is claimed.
    pub verified_at: Nullable<i64>,
}

/// One human-readable rebuild route: `verb ← sources` plus the
/// source-availability dot.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct RouteInfo {
    pub route: String,
    /// Every input blob currently resident.
    pub source_present: bool,
    pub verify: RouteVerify,
}

// ---- POST /v1/dats/import ----

/// One import's receipt — the same fields `datboi dat import --json`
/// prints, plus the resolved source identity (the web caller never saw
/// the dat header, so it can't derive provider/system itself).
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct DatImportResponse {
    /// The dat source this landed in — the `/v1/systems` id.
    pub source_id: i64,
    pub revision_id: i64,
    /// blake3 of the dat blob now in the CAS, lowercase hex.
    pub dat_blob: String,
    /// Resolved provider (override, else derived from the dat header —
    /// homepage when it names an org, else author).
    pub provider: String,
    /// Resolved system (override, else the dat header's name).
    pub system: String,
    pub entries: u64,
    pub claims: u64,
    /// Revisions demoted to header-only by this import (D38).
    pub demoted_revisions: Vec<i64>,
}

// ---- POST /v1/dats/fetch (D16/D96 auto-fetch) ----

/// Fetch a dat over HTTP and import it (Redump auto-fetch, D16).
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct DatFetchRequest {
    /// A full URL, or `redump/<system-slug>` (e.g. `redump/psx`).
    pub source: String,
    /// Provider override; `redump/...` defaults to "Redump", else the
    /// dat header decides.
    #[serde(default)]
    pub provider: Option<String>,
    /// System override; the dat header decides when absent.
    #[serde(default)]
    pub system: Option<String>,
}

/// A fetch receipt: the resolved URL that was fetched, plus the import
/// outcome (the artifact went through the normal import path — D15).
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct DatFetchResponse {
    /// The URL actually fetched (a `redump/...` source resolves here).
    pub url: String,
    /// The import receipt for the fetched dat.
    pub import: DatImportResponse,
}

// ---- GET /v1/views (+ detail) ----

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct ViewsResponse {
    pub views: Vec<ViewSummary>,
}

/// One view in the listing: the union of tagged views (things being
/// served) and stored ViewDefs (defined but maybe never evaluated).
/// Row/byte/created stats come from the decoded snapshot manifest; a
/// missing or undecodable snapshot just omits them — the listing must
/// not die of one damaged view.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct ViewSummary {
    pub name: String,
    /// Current snapshot hash (blake3 hex); null when defined but never
    /// evaluated.
    pub snapshot: Nullable<String>,
    /// Null for tagged views whose definition was deleted.
    pub definition: Nullable<Definition>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub rows: Option<u64>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub bytes: Option<u64>,
    /// Snapshot creation time, unix seconds.
    #[serde(skip_serializing_if = "Option::is_none")]
    pub created_at: Option<u64>,
}

/// ViewDef summary: dat ref, 1G1R mode, profile, image params (D62).
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct Definition {
    pub provider: String,
    pub system: String,
    pub template: String,
    pub one_g_one_r: Nullable<OneGOneR>,
    pub profile: Nullable<String>,
    pub image: Nullable<ImageParams>,
    pub mame_mode: Nullable<MameMode>,
}

/// 1G1R selection policy (D57).
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct OneGOneR {
    pub mode: OneGOneRMode,
    pub regions: Vec<String>,
    pub langs: Vec<String>,
}

/// FAT32 image parameters from the ViewDef (D62).
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct ImageParams {
    pub cluster_size: u32,
    /// MBR partition table vs superfloppy.
    pub partition: bool,
    pub label: Nullable<String>,
}

/// GET /v1/view-profiles: the built-in constraint profiles a view
/// definition may name (the target-device limits an evaluation checks
/// against — docs/views.md). Static built-in data; the define UI offers
/// these as the `profile` choice.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct ViewProfilesResponse {
    pub profiles: Vec<ViewProfile>,
}

/// One constraint profile. Mirrors `datboi-catalog`'s built-in `Profile`
/// (the CLI's `view profiles` renders the same three limits).
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct ViewProfile {
    pub name: String,
    /// Max bytes per path component (UTF-8).
    pub max_name_len: u64,
    /// Files larger than this don't fit the target at all; null = no
    /// ceiling (e.g. exFAT targets).
    pub max_file_size: Nullable<u64>,
    /// Directories with more children than this are reported; null = no
    /// limit enforced.
    pub max_dir_entries: Nullable<u64>,
}

/// PUT /v1/views/{name}: define or replace a view (D96 view authoring;
/// the CLI's `view define`). The name is the path segment — this body
/// is its definition. `one_g_one_r` and `mame_mode` are mutually
/// exclusive (families vs sets answer different questions); setting both
/// is a 400. Omitting all selection fields defines an all-entries view.
/// Mirrors the read-side [`Definition`], but with omittable optionals
/// (request convention: `T` for required, `Option<T>` + skip for
/// optional — see [`wire`]).
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct ViewDefineRequest {
    pub provider: String,
    pub system: String,
    /// Layout template. Placeholders `{entry}` / `{name}`; path
    /// separators inside expanded values are sanitized to `_`.
    pub template: String,
    /// `Some` = 1G1R over clone families with these priorities.
    #[serde(skip_serializing_if = "Option::is_none")]
    pub one_g_one_r: Option<OneGOneR>,
    /// Built-in constraint profile name (see `GET /v1/view-profiles`).
    /// An unknown name is a 400.
    #[serde(skip_serializing_if = "Option::is_none")]
    pub profile: Option<String>,
    /// `Some` = the view also reifies as a FAT32 image (D62).
    #[serde(skip_serializing_if = "Option::is_none")]
    pub image: Option<ImageParams>,
    /// `Some` = render a MAME listxml source as merge-mode sets.
    #[serde(skip_serializing_if = "Option::is_none")]
    pub mame_mode: Option<MameMode>,
}

/// PUT /v1/views/{name} result: the stored definition, echoed back so
/// the UI can render the view without a follow-up read.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct ViewDefineResponse {
    pub name: String,
    pub definition: Definition,
}

/// GET /v1/views/{name}: the summary plus serve endpoints and mint
/// status.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct ViewDetail {
    #[serde(flatten)]
    pub summary: ViewSummary,
    pub endpoints: Endpoints,
    /// Mint status when the definition carries image params; null when
    /// it does not.
    pub image: Nullable<ImageStatus>,
}

/// Relative serve endpoints; DAV is loopback-only in M5 (D68).
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct Endpoints {
    pub http: String,
    pub dav: String,
}

/// D62 mint status: the `image/<name>` tag, when present, is a minted
/// FAT32 image for this view.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct ImageStatus {
    pub minted: bool,
    /// blake3 hex of the minted image; omitted when unminted.
    #[serde(skip_serializing_if = "Option::is_none")]
    pub hash: Option<String>,
    /// Image size; omitted when unminted, null when the blob row has
    /// no recorded size (outer Option/inner Nullable = absent/null).
    #[serde(skip_serializing_if = "Option::is_none")]
    pub bytes: Option<Nullable<u64>>,
}

