// ---- GET /v1/storage ----

/// Storage stats from the blob index — the same truth `datboi status`
/// reports, without an NFS metadata walk.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct StorageResponse {
    /// Data-namespace blobs in the index.
    pub blob_count: i64,
    /// Resident bytes.
    pub on_disk_bytes: i64,
    /// Resident + evicted-covered bytes (what the collection
    /// represents).
    pub represented_bytes: i64,
    /// Resident bytes with no non-failed rebuild route — the "can't
    /// shrink yet" tax.
    pub literal_only_bytes: i64,
    pub quarantine: Quarantine,
    /// Newest finished scrub from the D74 ledger; null before the
    /// first recorded run.
    pub last_scrub: Nullable<LastScrub>,
}

/// The scrub-run ledger readout (D74 rows, kind scrub).
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct LastScrub {
    /// Unix seconds the run finished.
    pub finished_at: i64,
    /// The run's ledger name (carries the sample %).
    pub name: String,
}

/// D49 rule 3: components whose seek path produced bad bytes.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct Quarantine {
    pub count: u64,
    pub items: Vec<QuarantineItem>,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct QuarantineItem {
    /// Component blob hash (blake3 hex).
    pub component: String,
    /// Unix seconds.
    pub quarantined_at: i64,
    pub reason: String,
}

// ---- GET /v1/storage/breakdown ----

/// Where the bytes live: the debug-grade aggregate behind the storage
/// screen — per-(namespace, residency) accounting, dat-source
/// attribution, and the largest blobs.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct StorageBreakdown {
    pub by_class: Vec<ClassBytes>,
    pub by_source: Vec<SourceBytes>,
    /// Top 50 data-namespace blobs by size.
    pub largest: Vec<BlobRow>,
}

/// One (namespace, residency) cell of the blob index.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct ClassBytes {
    /// `data` | `meta` (D20).
    pub namespace: String,
    pub residency: ResidencyState,
    pub blobs: i64,
    /// SUM(size) with NULL sizes counted as 0; `sizeless` says how many.
    pub bytes: i64,
    /// Blobs in this cell with no recorded size.
    pub sizeless: i64,
}

/// Data-namespace bytes attributed to one dat source via identity
/// links (identity_blob → rom_claim → entry → the source's CURRENT
/// dat_revision). A blob claimed by several sources counts in EACH
/// row — the column does not sum to the store. Blobs with no identity
/// link at all fold into the `(unattributed)` row.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct SourceBytes {
    /// `provider/system`, or `(unattributed)`.
    pub source: String,
    pub blobs: i64,
    pub bytes: i64,
}

// ---- GET /v1/blobs ----

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct BlobsPage {
    pub blobs: Vec<BlobRow>,
    /// The FILTERED count; the offset/limit window slides under it.
    pub total: i64,
    pub offset: u64,
    pub limit: u64,
}

/// One blob-index row with its graph degree — enough to answer "what
/// is this?" at listing granularity (`GET /v1/blobs/{hash}` expands
/// the edges).
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct BlobRow {
    /// blake3, lowercase hex.
    pub hash: String,
    pub size: Nullable<i64>,
    /// `data` | `meta` (D20).
    pub namespace: String,
    pub residency: ResidencyState,
    /// Last full-hash store verification, unix seconds.
    pub verified_at: Nullable<i64>,
    /// source_file provenance rows naming this blob.
    pub sources: u64,
    /// Non-poisoned recipes producing it (D25: `failed` never counts).
    pub routes_in: u64,
    /// Non-poisoned recipes consuming it.
    pub routes_out: u64,
}

// ---- GET /v1/blobs/{hash} ----

/// The blob inspector: identity, digests, provenance, the one-hop
/// recipe-DAG neighborhood, satisfied claims, and pinning views. The
/// listing row's degree counts materialize here as the actual lists
/// (claims capped at 100 — `claims_total` is uncapped).
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct BlobDetail {
    /// blake3, lowercase hex.
    pub hash: String,
    pub size: Nullable<i64>,
    /// `data` | `meta` (D20).
    pub namespace: String,
    pub residency: ResidencyState,
    pub verified_at: Nullable<i64>,
    pub digests: BlobDigests,
    pub provenance: Vec<ProvenanceRow>,
    /// Source paths carried by recipe-CONNECTED blobs (D79 viral
    /// provenance display): where these bytes actually arrived, for
    /// derived/member blobs whose own `provenance` is empty. Capped
    /// at 10.
    pub provenance_via: Vec<ProvenanceViaRow>,
    /// Recipes whose OUTPUT is this blob — ways to make it.
    pub routes_in: Vec<RouteEdge>,
    /// Recipes consuming this blob as an input — things made from it.
    pub routes_out: Vec<RouteEdge>,
    /// Capped at 100 rows; `claims_total` is the uncapped count.
    pub claims: Vec<ClaimRef>,
    pub claims_total: u64,
    /// Claimed blobs this blob is connected to through the recipe DAG
    /// (D79): the display identity when `claims` is empty. Capped at
    /// 20; empty for a truly unattached blob.
    pub roots: Vec<RootRef>,
    /// Magic-byte sniff of resident bytes ("zip archive", …) — a
    /// display hint, never identity (D18: type lives in the edges).
    /// Null when absent from disk or unrecognized.
    pub sniff: Nullable<String>,
    /// Views whose CURRENT snapshot references this blob (D33: the tag
    /// is what pins).
    pub pins: Vec<String>,
}

/// A claimed root reachable from a blob through recipe edges (D79).
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct RootRef {
    /// The root blob (blake3 hex) — links into its own inspector.
    pub hash: String,
    /// Best claim name on the root.
    pub entry: String,
    /// provider/system of that claim.
    pub source: String,
    pub relation: RootRelation,
}

/// How the inspected blob relates to a claimed root, following
/// DIRECTED recipe edges (input → output = "helps make").
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
#[serde(rename_all = "snake_case")]
pub enum RootRelation {
    /// The blob is an upstream ingredient: some recipe chain assembles
    /// the root FROM it (chunks, containers, preflate streams).
    Makes,
    /// The blob is a downstream product of the root (stripped bodies,
    /// extracted variants).
    DerivedFrom,
    /// Connected through the DAG but on a sibling branch (e.g. a chunk
    /// of rom A reaching rom B through their shared container).
    Related,
}

/// One viral-provenance row (D79): a source path recorded on a
/// recipe-connected blob, shown on blobs that have none of their own.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct ProvenanceViaRow {
    pub path: String,
    /// When the path was last scanned/ingested, unix seconds.
    pub ingested_at: Nullable<i64>,
    /// The connected blob (blake3 hex) actually carrying the path.
    pub via: String,
}

/// Every digest the index holds for the blob's bytes: the blake3 key
/// plus recorded alias digests (D22). The declared CHD sha1 alias is
/// excluded — it attests decompressed content, not these bytes (D44).
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct BlobDigests {
    /// The identity, lowercase hex.
    pub blake3: String,
    #[serde(flatten)]
    pub aliases: RomHashes,
}

/// One rescan-cache row: a filesystem path that hashed to this blob.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct ProvenanceRow {
    pub path: String,
    /// When the path was last scanned/ingested, unix seconds.
    pub ingested_at: Nullable<i64>,
}

/// One recipe edge of the DAG neighborhood, navigable — every
/// [`HashRef`] resolves at `GET /v1/blobs/{hash}`. Poisoned (`failed`)
/// recipes never surface (D25 terminal).
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct RouteEdge {
    /// The op as recorded: builtin `name@major`, wasm `<hex>#export`.
    pub op: String,
    pub verify: RouteVerify,
    pub inputs: Vec<HashRef>,
    pub outputs: Vec<HashRef>,
}

/// A blob reference inside a route edge.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct HashRef {
    /// blake3, lowercase hex.
    pub hash: String,
    pub size: Nullable<i64>,
    /// The recipe_output member name (or recipe_input role), when
    /// recorded.
    pub name: Nullable<String>,
}

/// One dat claim this blob satisfies, via identity links of any
/// evidence grade (current revisions only).
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct ClaimRef {
    /// Entry name within the source's current revision.
    pub entry: String,
    /// `provider/system` display identity.
    pub source: String,
}

// ---- POST /v1/ingest/uploads ----

/// One staged upload's receipt.
