pub struct UploadResponse {
    /// Opaque staging token — spend it in `POST /v1/ingest`. Tokens
    /// are in-memory: a daemon restart forgets them (the staged bytes
    /// are swept with the rest of the store's tmp/).
    pub upload: String,
    /// Bytes received and staged.
    pub bytes: u64,
}

// ---- POST /v1/ingest ----

/// Start an ingest job over staged uploads.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct IngestRequest {
    /// Staging tokens from `POST /v1/ingest/uploads`, spent
    /// all-or-nothing.
    pub uploads: Vec<String>,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct IngestStartResponse {
    /// Poll `GET /v1/jobs/{id}` for progress and the report.
    pub job: i64,
}

// ---- POST /v1/blobs/{hash}/verify (D80) ----

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct VerifyStartResponse {
    /// Poll `GET /v1/jobs/{id}`; done stamps `verified_at`, failed
    /// carries the corruption evidence in `error`.
    pub job: i64,
}

/// A started background job (D96 view verbs: eval, mint; maintenance
/// verbs: scrub). Poll `GET /v1/jobs/{id}` for progress; the finished
/// job's report carries the outcome, a failed one carries `error`.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct JobStartResponse {
    pub job: i64,
}

// ---- POST /v1/scrub (D96 maintenance) ----

/// Trigger a corpus scrub over serve — the same walk `datboi scrub`
/// runs (verify bytes against names, back-fill aliases + `verified_at`,
/// pack integrity, optional recipe rehabilitation). Long-running, so it
/// answers a `JobStartResponse`; the finished Scrub job's notes carry
/// the checked/refreshed/corrupt/missing summary.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct ScrubRequest {
    /// Percentage of loose blobs to check (deterministic sample by hash
    /// prefix); packs are always scrubbed whole when this is non-zero.
    /// Defaults to 100 (a full pass), matching the CLI.
    #[serde(default)]
    pub sample_pct: Option<u8>,
    /// Re-execute poisoned (Failed) recipes; a verified re-replay clears
    /// the poison. Defaults to false.
    #[serde(default)]
    pub rehabilitate: Option<bool>,
}

// ---- POST /v1/sweep (D96 on-demand refinement) ----

/// Run one analyzer sweep round on demand — the manual equivalent of the
/// ambient refiner's per-family drain (D71). Long-running (a preflate
/// split is minutes), so it answers a `JobStartResponse`; the finished
/// Refine job's note carries the enqueued/analyzed/positive/negative
/// counts and the remaining queue depth.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct SweepRequest {
    /// Analyzer name (canonical or CLI alias): noop, chunk, preflate,
    /// ecm, nds, narc.
    pub analyzer: String,
    /// Maximum items to analyze this round. Defaults to 10000 (the CLI
    /// default).
    #[serde(default)]
    pub limit: Option<u64>,
}

// ---- POST /v1/snapshot (D75/D96 manual trigger) ----

/// The report of one minted state snapshot — the same numbers `datboi
/// snapshot` prints. Content-dedup means an unchanged shard costs no new
/// batch blob, so `new_batch_blobs` is the actual write amplification.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct SnapshotResponse {
    /// The minted snapshot object's blake3 (64 hex chars).
    pub hash: String,
    /// Monotonic snapshot sequence number.
    pub sequence: i64,
    /// Dat sources captured.
    pub sources: u64,
    /// Alias rows batched across the shard fanout.
    pub alias_rows: u64,
    /// Analysis rows batched.
    pub analysis_rows: u64,
    /// Batch blobs newly written this mint (unchanged shards dedup away).
    pub new_batch_blobs: u64,
}

// ---- POST /v1/evict (D72/D96 on-demand eviction) ----

/// Reclaim resident bytes by evicting recipe-covered literals (D25/D72).
/// `dry_run` reports the plan without deleting (the preview surface);
/// otherwise the drop runs under the D72 singleton guard as a background
/// Gc job — a 202 with a job id, or a 503 if the guard is already held.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct EvictRequest {
    /// Evict until at most this many resident bytes remain.
    pub target_bytes: u64,
    /// License (replay) covered routes first, so routes that have not
    /// yet replayed on this host become evictable too. Defaults to false.
    #[serde(default)]
    pub license: Option<bool>,
    /// Report the plan without deleting anything. Defaults to false.
    #[serde(default)]
    pub dry_run: Option<bool>,
}

/// One candidate the plan cannot drop right now, with the D25/D27 reasons
/// spelled out (a residency planner that says "0 evicted" without saying
/// why loses trust).
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct EvictBlocked {
    pub hash: String,
    pub reasons: Vec<String>,
}

/// The dry-run eviction plan: what would drop, and what is held back.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct EvictPlan {
    /// Blobs that would be evicted at the current target.
    pub evictable: u64,
    /// Bytes those evictions would reclaim.
    pub reclaimable_bytes: u64,
    /// Candidates held back, each with its reasons.
    pub blocked: Vec<EvictBlocked>,
}

// ---- GET /v1/jobs (+ /{id}) ----

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct JobsResponse {
    pub jobs: Vec<Job>,
}

/// What a job is doing. Under D96 the expensive view verbs graduated to
/// background jobs on the serve surface (eval, mint); evict/sweep follow.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
#[serde(rename_all = "lowercase")]
pub enum JobKind {
    Ingest,
    /// A refinement drain (D71): the daemon's ambient analyzer worker
    /// chewing through one family's sweep queue. `files_*`/`bytes_*`
    /// in the detail count ITEMS (blobs), not files/bytes.
    Refine,
    /// GC-family maintenance (D72/D73): licensing drains, watermark
    /// evictions, orphan applies. Item counts, like refine.
    Gc,
    /// A scrub pass (CLI-recorded via the D74 ledger; the run ledger
    /// the storage screen wants).
    Scrub,
    /// A view evaluation → immutable snapshot (D96): the CLI's `view
    /// eval`, run as a background job on the serve surface.
    Eval,
    /// A FAT32 image mint for a view (D62/D96): the CLI's `view image`.
    Mint,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
#[serde(rename_all = "lowercase")]
pub enum JobRunState {
    Running,
    Done,
    Failed,
}

/// One row of the job registry (running + D74 ledger history — the
/// activity page render, D82).
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct Job {
    pub id: i64,
    /// Display name, e.g. `ingest — 3 files`.
    pub name: String,
    /// 0–100, byte-weighted at FILE granularity (the pipeline reports
    /// no intra-file progress); clamped to 99 while running so only a
    /// finished job reads 100.
    pub progress: u8,
    pub kind: JobKind,
    pub state: JobRunState,
    /// Unix seconds. On the LIST row, not just the detail, because the
    /// activity page renders relative timestamps for every row and
    /// must not need N+1 detail fetches to do it (D82).
    pub started_at: i64,
    /// Unix seconds; null while running.
    pub finished_at: Nullable<i64>,
}

/// GET /v1/jobs/{id}: the row plus counters and the (growing, then
/// final) report. File paths in the report are the CLIENT's original
/// names — staging paths never leak.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct JobDetail {
    #[serde(flatten)]
    pub job: Job,
    pub files_total: u64,
    pub files_done: u64,
    pub bytes_total: u64,
    pub bytes_done: u64,
    /// Original name of the file being processed; omitted between
    /// files and once finished.
    #[serde(skip_serializing_if = "Option::is_none")]
    pub current: Option<String>,
    // started_at / finished_at moved onto the flattened `Job` row —
    // this struct's JSON shape is unchanged.
    /// Cumulative across completed files — grows while running, final
    /// when done.
    pub report: IngestReportBody,
    /// Entries this job's content NEWLY satisfied (the shelf lights).
    /// Capped at 200 rows; `matched_total` is the uncapped count.
    pub matched: Vec<MatchedEntry>,
    pub matched_total: u64,
    /// Infrastructure failure only; per-file refusals live in the
    /// report.
    pub error: Nullable<String>,
}

// ---- GET /v1/gc/orphans (+ keep / apply) ----

/// One reviewable orphan (D73): unreferenced past the grace window,
/// still unrooted as of the last sweep. The mark is REVIEW state —
/// apply re-verifies reachability at delete time.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct OrphanItem {
    pub hash: String,
    pub size: u64,
    /// Unix seconds of first-observed-unreferenced (the grace clock).
    pub marked_at: i64,
    /// Ingest paths that ever carried these bytes — the context a
    /// reviewer needs to say junk-or-keep.
    pub sources: Vec<String>,
    /// Operator keep-mark: excluded from apply until unkept.
    pub kept: bool,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct OrphansResponse {
    pub orphans: Vec<OrphanItem>,
    /// Bytes across non-kept candidates (what apply-all would free).
    pub reclaimable_bytes: u64,
    pub grace_secs: i64,
}

/// Set or clear a keep-mark ("this is not junk").
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct GcKeepRequest {
    pub hash: String,
    pub keep: bool,
}

/// Apply the reviewed set (D73: the ONE human-triggered destructive
/// action). Absent `hashes` = every reviewable, non-kept candidate.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct GcApplyRequest {
    #[serde(skip_serializing_if = "Option::is_none")]
    pub hashes: Option<Vec<String>>,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct GcApplyResponse {
    pub deleted: u64,
    pub bytes_reclaimed: u64,
    /// Requested but refused at delete-time re-verification (rooted
    /// since review, kept, or not aged) — never an error, always
    /// visible.
    pub skipped: u64,
}

// ---- GC policy (D72/D73/D96): GET + PUT /v1/gc/config ----

/// The eviction/GC policy: high/low watermarks (canonical `off` / `NN%`
/// / absolute-bytes strings) and the orphan grace window in seconds.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct GcConfig {
    pub high_water: String,
    pub low_water: String,
    pub grace_secs: i64,
}

/// PUT /v1/gc/config: set any subset of the policy. Each omitted field
/// is left unchanged; a malformed watermark or negative grace is a 400.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct GcConfigRequest {
    #[serde(skip_serializing_if = "Option::is_none")]
    pub high_water: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub low_water: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub grace_secs: Option<i64>,
}

/// One dat entry an ingest job newly satisfied — the user-vocabulary
/// half of the report (games, not blob counts).
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct MatchedEntry {
    pub name: String,
    /// `provider/system` display identity.
    pub source: String,
}

/// The ingest pipeline's report (datboi-ingest `IngestReport`), as
/// wire JSON. Same counters the CLI prints.
#[derive(Debug, Clone, Default, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct IngestReportBody {
    pub files_scanned: u64,
    /// Rescan-cache hits: same path, mtime, and size as last time.
    pub files_unchanged: u64,
    /// New blobs stored.
    pub files_stored: u64,
    /// Content already in the store (dupes).
    pub files_already_present: u64,
    pub chd_v5: u64,
    /// Zip members claimed in place (the container stays the literal).
    pub members_claimed: u64,
    /// 7z/rar members extracted as resident blobs.
    pub members_extracted: u64,
    pub detector_hits: u64,
    /// Files over the skipper sniff cap — stored, but not
    /// detector-checked.
    pub skipper_skipped_large: u64,
    /// Files the job classified (by content) as dats — loose or the
    /// sole member of a zip — and imported instead of ingesting. Its
    /// own lane: pipeline counters above stay pure, a dat import is
    /// not a `files_scanned`.
    pub dats_imported: Vec<DatImportedItem>,
    pub errors: Vec<IngestErrorItem>,
    pub member_skips: Vec<IngestMemberSkipItem>,
    pub notes: Vec<String>,
}

/// One dat an ingest job imported (the unified drop surface: content
/// classifies each file as dat / zipped dat / ROM — names never
/// decide).
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct DatImportedItem {
    /// The client's original name for the file.
    pub path: String,
    /// Resolved provider/system — the `/v1/systems` identity the dat
    /// landed in (the caller never saw the dat header).
    pub provider: String,
    pub system: String,
    pub entries: u64,
}

/// A file the pipeline could not process.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct IngestErrorItem {
    /// The client's original name for the file.
    pub path: String,
    pub error: String,
}

/// An archive member the pipeline refused (zip64, encrypted,
/// unsupported method, central-directory lies, …).
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, ToSchema)]
pub struct IngestMemberSkipItem {
    /// The client's original name for the container.
    pub path: String,
    pub member: String,
    pub reason: String,
}

